SITES = [{"slug": "boudreauxs", "name": "Boudreaux’s Restaurant", "conversion": "groups.html"}, {"slug": "eddies-place", "name": "Eddie’s Place", "conversion": "gatherings.html"}, {"slug": "salud-cerveceria", "name": "Salud Cerveceria", "conversion": "events.html"}, {"slug": "the-degenerate", "name": "The Degenerate", "conversion": "night-planner.html"}, {"slug": "growlers-pourhouse", "name": "Growlers Pourhouse", "conversion": "pairing.html"}, {"slug": "the-goodyear-house", "name": "The Goodyear House", "conversion": "reservations.html"}, {"slug": "the-daily-tavern", "name": "The Daily Tavern", "conversion": "game-day.html"}, {"slug": "artisans-palate", "name": "The Artisan’s Palate", "conversion": "events.html"}, {"slug": "intermezzo-pizzeria", "name": "Intermezzo Pizzeria", "conversion": "family-table.html"}, {"slug": "euro-grill-cafe", "name": "Euro Grill & Café", "conversion": "catering.html"}, {"slug": "midtown-tavern", "name": "Midtown Tavern", "conversion": "watch-party.html"}, {"slug": "the-hobbyist", "name": "The Hobbyist", "conversion": "day-to-night.html"}, {"slug": "enderly-coffee", "name": "Enderly Coffee Co.", "conversion": "coffee-finder.html"}, {"slug": "giddy-goat-coffee", "name": "Giddy Goat Coffee Roasters", "conversion": "brew-match.html"}, {"slug": "harpers-cafe-pineville", "name": "Harper’s Cafe", "conversion": "meal-planner.html"}, {"slug": "middle-james-brewing", "name": "Middle James Brewing", "conversion": "events.html"}, {"slug": "kits-trackside-crafts", "name": "Kit’s Trackside Crafts", "conversion": "tap-events.html"}, {"slug": "pintville-craft-beer", "name": "Pintville Craft Beer", "conversion": "gatherings.html"}, {"slug": "miro-spanish-grille", "name": "Miro Spanish Grille", "conversion": "celebrations.html"}, {"slug": "zinicola", "name": "Zinicola", "conversion": "private-dining.html"}]

class LinkParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.links=[]
        self.current=0
        self.title=False
    def handle_starttag(self,tag,attrs):
        a=dict(attrs)
        if tag=="a" and "href" in a:
            self.links.append(a["href"])
        if tag=="a" and a.get("aria-current")=="page":
            self.current+=1
        if tag=="title":
            self.title=True

def safe_extract(archive: tarfile.TarFile, root: Path) -> None:
    root_resolved=root.resolve()
    for member in archive.getmembers():
        target=(root/member.name).resolve()
        if root_resolved not in target.parents and target != root_resolved:
            raise RuntimeError(f"Unsafe archive path: {member.name}")
    archive.extractall(root)

def install_bundle(root: Path) -> None:
    payload=lzma.decompress(base64.b64decode(ARCHIVE_B64))
    with tarfile.open(fileobj=io.BytesIO(payload),mode="r:") as archive:
        safe_extract(archive,root)

def update_portal(root: Path) -> None:
    path=root/"index.html"
    text=path.read_text(encoding="utf-8")
    marker="const concepts=["
    if marker not in text:
        raise RuntimeError("Could not locate portal concepts array")
    missing=[card for card in CARDS if f'"href":"{card["href"]}"' not in text]
    if not missing:
        return
    insert=",".join(json.dumps(card,ensure_ascii=False,separators=(",",":")) for card in missing)+","
    pos=text.index(marker)+len(marker)
    path.write_text(text[:pos]+insert+text[pos:],encoding="utf-8")

def validate(root: Path) -> list[str]:
    failures=[]
    rows=[]
    for site in SITES:
        folder=root/site["slug"]
        required=["index.html","menu.html","story.html",site["conversion"],"visit.html"]
        missing=[name for name in required if not (folder/name).is_file()]
        if missing:
            failures.append(f'{site["name"]} missing: {", ".join(missing)}')
            continue
        for name in required:
            parser=LinkParser()
            parser.feed((folder/name).read_text(encoding="utf-8"))
            if not parser.title:
                failures.append(f'{site["name"]}/{name} missing title')
            if parser.current != 1:
                failures.append(f'{site["name"]}/{name} has {parser.current} current nav links')
            for href in parser.links:
                if href.startswith(("http://","https://","#","mailto:","tel:")):
                    continue
                target=(folder/href.split("#",1)[0])
                if href and not target.exists():
                    failures.append(f'{site["name"]}/{name} broken internal link: {href}')
        js=folder/"site.js"
        if js.exists():
            try:
                result=subprocess.run(["node","--check",str(js)],capture_output=True,text=True)
                if result.returncode:
                    failures.append(f'{site["name"]} JavaScript syntax failed: {result.stderr.strip()}')
            except FileNotFoundError:
                pass
        rows.append(f'| {site["name"]} | 5/5 | Full five-page demo — browser visual QA pending |')
    status=root/"BLOCK1_STATUS.md"
    status.write_text(
        "# Block 1 Status\n\n"
        "All entries below have five separate substantive pages and passed structural/internal-link validation. "
        "Browser-rendered desktop and mobile visual QA remains pending, so none are labeled premium.\n\n"
        "| Restaurant | Pages | Status |\n|---|---:|---|\n"+"\n".join(rows)+"\n",
        encoding="utf-8",
    )
    return failures

def main() -> None:
    root=Path(__file__).resolve().parents[1]
    install_bundle(root)
    update_portal(root)
    failures=validate(root)
    if failures:
        print("\n".join(failures))
        raise SystemExit(1)
    print(f"Installed and validated {len(SITES)} Block 1 restaurant demos.")

if __name__=="__main__":
    main()
